626	/// C: `void luaV_finishset(lua_State *L, const TValue *t, TValue *key,
627	///                          TValue *val, const TValue *slot)`
628	/// Finish a table-set with `__newindex` metamethod lookup.
629	pub(crate) fn finish_set(
630	    state: &mut LuaState,
631	    t_val: LuaValue,
632	    key: LuaValue,
633	    val: LuaValue,
634	    _slot_present: bool,
635	) -> Result<(), LuaError> {
636	    let mut t = t_val;
637	    for _loop in 0..MAX_TAG_LOOP {
638	        let tm: LuaValue;
639	        if matches!(t, LuaValue::Table(_)) {
640	            // C: tm = fasttm(L, h->metatable, TM_NEWINDEX)
641	            let mt = state.table_metatable(&t);
642	            tm = state.fast_tm_table(mt.as_ref(), TagMethod::NewIndex);
643	            if matches!(tm, LuaValue::Nil) {
644	                // C: luaH_finishset(L, h, key, slot, val); invalidate; barrier; return;
645	                state.table_raw_set(&t, key, val.clone())?;
646	                state.gc_barrier_back(&t, &val);
647	                return Ok(());
648	            }
649	        } else {
650	            // C: tm = luaT_gettmbyobj(L, t, TM_NEWINDEX)
651	            // C: if (notm(tm)) luaG_typeerror(L, t, "index");
652	            tm = state.get_tm_by_obj(&t, TagMethod::NewIndex);
653	            if matches!(tm, LuaValue::Nil) {
654	                return Err(LuaError::type_error(&t, "index"));
655	            }
656	        }
657	        // C: if (ttisfunction(tm)) { luaT_callTM(L, tm, t, key, val); return; }
658	        if matches!(tm, LuaValue::Function(_)) {
659	            state.call_tm(tm, &t, &key, &val)?;
660	            return Ok(());
661	        }
662	        // C: t = tm; luaV_fastget again
663	        t = tm.clone();
664	        if state.fast_get(&t, &key)?.is_some() {
665	            // C: luaV_finishfastset(L, t, slot, val)
666	            state.table_raw_set(&t, key.clone(), val.clone())?;
667	            state.gc_barrier_back(&t, &val);
668	            return Ok(());
669	        }
670	    }
671	    Err(LuaError::runtime(format_args!("'__newindex' chain too long; possible loop")))
672	}
