/// C: `void luaV_finishset(lua_State *L, const TValue *t, TValue *key,
///                          TValue *val, const TValue *slot)`
/// Finish a table-set with `__newindex` metamethod lookup.
pub(crate) fn finish_set(
    state: &mut LuaState,
