                        let ra_v = state.get_at(ra_idx).clone();
                        let imm = state.proto_const(&cl, i.arg_b() as usize).clone();
                        let tm = tagmethod_from_index(i.arg_c() as usize);
                        let flip = i.arg_k() != 0;
