                        trap = state.ci_trap(ci);
                    }
                    // ── OP_EQ ─────────────────────────────────────────────────
                    // C: Protect(cond = luaV_equalobj(L, s2v(ra), rb)); docondjump()
                    OpCode::Eq => {
