                    //    else { ci = newci; goto startfunc; }
                    OpCode::Call => {
                        let ra = base + i.arg_a();
                        let b = i.arg_b();
                        let nresults = i.arg_c() as i32 - 1;
                        if b != 0 {
                            state.set_top(ra + b);
                        }
                        state.set_ci_savedpc(ci, pc); // savepc
                        match state.precall(ra, nresults)? {
                            None => {
                                // C function — nothing else to do
                                trap = state.ci_trap(ci); // updatetrap
                            }
                            Some(new_ci) => {
