/// Pops the error value from the stack and wraps it.
/// TODO(phase-b): expose as `LuaError::from_top` in lua-types.
fn runtime_from_top(state: &mut crate::state::LuaState) -> LuaError {
    let v = state.pop();
    LuaError::Runtime(v)
