// C: #define LuaClosure(f) ((f) != NULL && (f)->c.tt == LUA_VLCL)
// macros.tsv: LUA_VLCL → LuaClosure::Lua(_)
#[inline]
fn is_lua_closure(cl: Option<&LuaClosure>) -> bool {
